        /* <flatten type="Javascript"> */
var f = this, v = (f._language == 'v');
var e1 = (v ? 'Mã bộ phận trùng nhau trong phần thông tin chi tiết.' : 'Invalid department, it already exists.');
var e2 = (v ? 'Đơn giá phải giống nhau trong phần thông tin chi tiết.' : 'The price must be the same in the detail information.');
var g = f.getItem('dcc')._controlBehavior;
var a = query$Select(g, 'count$1 $groupBy ma_bp_dc');
var b = query$Select(g, 'count$1 $groupBy gia');
for (var i = 0; i < a.length; i++) {
  if (a[i][1] > 1) {on$Voucher$Error(this, e1, 'dcc'); break;}
}
if (f._checked) {
  a = query$Select(g, 'count$1 $groupBy gia_nt');
  if (a.length > 1) {
    for (var i = 0; i < a.length; i++) {
      if (a[i][1] == 1 || b[i][1] == 1) {on$Voucher$Error(this, e2, 'dcc'); break;}
    }
  }
}
if (f._checked) {
  var d1 = new Date(f._dateLimitedFrom), d2 = new Date(f._dateLimitedTo), e2 = $df.getResources(f._language, 'Message.RequiredField');
  a = ['ngay_pb0', 'ngay_pb_kt', 'ngay_lct', 'ngay_tang', 'ngay_dc'];
  for (var i = 0; i < a.length; i++) {
    if (!f._checked) break;
    var d = f.getItemValue(a[i]);
    if (d) check$Limited$Date(this, d, d1, d2, a[i], e2);
  }
}
