script.text:
      &ScriptQueryData;
      &ScriptVoucherInit;

function init$Voucher$(f) {}
function active$Voucher$(f) {&ScriptActiveVoucher;
  objectBehavior$Dir$Code.create(f, '&PrimaryField;', '&PrimaryField;', '&PrimaryTable;');
  f._tabContainer.add_activeTabChanged(onChange$Voucher$Tab);
  f._tabContainer._loaded = true;
  f._ma_cu = $func.trim(f.getItemValue('&PrimaryField;'));
  on$Voucher$AllocationType$Change(f);
  &ListCreate;
  &PostCreate;
}
function scatter$Voucher$(f) {&ScriptScatterVoucher;
  if (f._action != 'View') on$Voucher$AllocationType$Change(f);
}
function close$Voucher$(f) {&ScriptCloseVoucher;
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onChange$Voucher$Tab);} catch (ex) {}
  objectBehavior$Dir$Code.dispose(f);
  &ListDispose;
  &PostDispose;
}
function on$Voucher$ExecuteCommand(sender, e) {
  var action = e.type.Action, f = sender, g = f.getItem('dcc')._controlBehavior, y = f.getItem('acc')._controlBehavior;
  switch (action) {
    case 'Gather':
      g.setSequenceNumber('line_nbr');
      g.setContinuance('stt_rec0');
      y.setSequenceNumber('line_nbr');
      y.setContinuance('stt_rec0');
      break;
    case 'Shown':
      &ListShown;
      &PostShown;
      break;
    default:
      break;
  }
}
/* <flatten type="Javascript"> */
function check$Limited$Date(f, d, d1, d2, id, err) {
  if (d < d1 || d > d2) {
    f._checked = false;
    $func.hideWait(f.get_id());
    $message.show(String.format(err, f.getItem(id).field.Label), String.format('$find(\'{0}\').focus(\'{1}\');', f.get_id(), id));
    break;
 }
}
/* </flatten> */
      &ScriptVoucherNumber;

objectBehavior$Voucher$Currency = {
&ScriptCurrency;
  create: function(f) {
    var d = f.getItem('ngay_lct'), p = f.getItem('ngay_ct'), c = f.getItem('ma_nt'), r = f.getItem('ty_gia'), g = f.getItem('dcc')._controlBehavior, y = f.getItem('acc')._controlBehavior;
    var v = f._currencyBehavior = $create(FastBusiness.AjaxControlExtender.Currency, {id: f._id + '_currencyBehavior', currencyDate: d, referenceDate: p, exchangeRate: r, form: f, baseCurrency: f._baseCurrency, flush: true}, null, null, c);
    v.set_currencyFields('t_nguyen_gia_nt,t_gt_da_pb_nt,t_gt_cl_nt,t_gt_pb_ky_nt:t_nguyen_gia,t_gt_da_pb,t_gt_cl,t_gt_pb_ky');
    v.addGridFields(g, 'gia_nt,nguyen_gia_nt,gt_da_pb_nt,gt_cl_nt,gt_pb_ky_nt:gia,nguyen_gia,gt_da_pb,gt_cl,gt_pb_ky');
    v.addTotalFields(g, [['t_nguyen_gia_nt', 'nguyen_gia_nt'], ['t_gt_da_pb_nt', 'gt_da_pb_nt'], ['t_gt_cl_nt', 'gt_cl_nt'], ['t_gt_pb_ky_nt', 'gt_pb_ky_nt'], ['t_nguyen_gia', 'nguyen_gia'], ['t_gt_da_pb', 'gt_da_pb'], ['t_gt_cl', 'gt_cl'], ['t_gt_pb_ky', 'gt_pb_ky']]);
    v.addGridFields(y, 'gia_tri_nt : gia_tri');
    v.set_referenceFields(null);
&CurrencyDateChanged;
  onCurrencySelected: function(sender, e) {if (e.object._baseCurrency == e.type) e.object._form.getItem('tk_dc').focus();}
}
function onChange$Voucher$Tab(sender, e) {
  sender.parentForm.focusWhenTabChanged(['dcc', 'acc', 'ten_dc2'&ListTabChange;&PostTabChange;, 't_nguyen_gia_nt'], '');
  &PostTabFocus;
}
/* <flatten type="Javascript"> */
function onChange$Voucher$AllocationMethod(o) {
  var f = o.parentForm; var k = f.getItem('so_ky_pb'), d = f.getItem('ngay_pb_kt'), v = (f.getItemValue('kieu_pb') == 0);
  d.field.AllowNulls = v;
  window.setTimeout(String.format('onFocus$Voucher$AllocationMethod(\'{0}\', \'{1}\', \'{2}\', \'{3}\', {4});', f._id, o.id, k.id, d.id, v ? 1 : 0), 2);
}
function onFocus$Voucher$AllocationMethod(c1, c2, c3, c4, v) {
  var f = $find(c1), o = $get(c2), k = $get(c3), d = $get(c4);
  if (v && d.live) {
    on$Voucher$AllocationType$Change(f);
    k.focus();
    f.live(k);
  }
  if (!v && k.live) {
    d.focus();
    f.live(d);
  }
  if (!v) {
    on$Voucher$AllocationType$Change(f);
    setAllocationValue(o);
  }
}
function onChange$Voucher$AllocationStartDate(o) {
  var f = o.parentForm, d = f.getItem('ngay_pb_kt');
  if (f.getItemValue('so_ky_pb') != 0) increaseDays(f, d);
    else f.setItemValue('ngay_pb_kt', null);
}
function onChange$Voucher$AllocationPeriods(o) {
  var f = o.parentForm, d = f.getItem('ngay_pb_kt');
  setAllocationValue(o);
  if (o.value != 0) increaseDays(f, d);
    else f.setItemValue('ngay_pb_kt', null);
  f.live(f.getItem('ngay_pb_kt'));
}
/* </flatten> */
function on$Voucher$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Loading':
      &VoucherNumberLoading;
      break;
    case 'Scattering':
      &VoucherNumberScattering;
      &ListScattering;
      &PostScattering;
      break;
    case 'Navigating':
      &ListRefresh;
      &PostRefresh;
      break;

      &VoucherNumberReading;
      &CurrencyResponse;
      &ListResponseTicket;

    case 'Suggestion':
      objectBehavior$Dir$Code.suggestion(f, result[0].Value);
      break;
    case 'Checking':
      objectBehavior$Dir$Code.checkCode(f);
      break;
    default:
      break;
  }
}
/* <flatten type="Javascript"> */
function on$Voucher$Error(f, errorMessage, c) {
  f._checked = false;
  $func.hideWait(f.get_id());
  $message.show(errorMessage, String.format('$find(\'{0}\').focus(\'{1}\');', f.get_id(), c));
}
function on$Voucher$AllocationType$Change(f) {
  var v = (f.getItemValue('kieu_pb') != 0);
  if (v) f.setItemValue('so_ky_pb', 2);
  f.getItem('so_ky_pb').disabled = v;
}
function increaseDays(f, o) {
  var v = f.getItemValue('ngay_pb0', null, null, true), p = f.getItemValue('so_ky_pb'), n = 0;
  if (!v) return;
  if (f.$_method) {
    n = v.getDate();
    if (n > 28) {
     var k = (new Date(v.getFullYear(), v.getMonth() + p + 1, 0)).getDate();
     if (n > k) n = k;
    }
    n -= 1;
  }
  d = new Date(v.getFullYear(), v.getMonth() + p, n);
  o._controlBehavior.set_selectedDate(d);
}
function setAllocationValue(o) {
  var f = o.parentForm; var g = f.getItem("dcc")._controlBehavior;
  for (var i = 0; i < g._rowCount; i++) {
    g.assignExpression(i, '[gt_pb_ky_nt]:= [Rso_ky_pb] == 0 ? 0 : [nguyen_gia_nt]/[Rso_ky_pb]');
    g.assignExpression(i, '[gt_pb_ky]:= [Rso_ky_pb] == 0 ? 0 : [nguyen_gia]/[Rso_ky_pb]');
  }
  g.executeAggregate([['t_gt_pb_ky_nt', 'gt_pb_ky_nt'], ['t_gt_pb_ky', 'gt_pb_ky']]);
}
/* </flatten> */
      &ScriptSuggestion;
      &ListScript;
      &PostScript;
